## Recommended Hardened Baseline

Here is a consolidated secure starting point that addresses all findings:

```js
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');

const app = express();

// 1. Trust proxy if behind nginx/ALB
app.set('trust proxy', 1);

// 2. Security headers
app.use(helmet());

// 3. CORS — allowlist only
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  credentials: true,
}));

// 4. Access logging
app.use(morgan('combined'));

// 5. Body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// 6. Rate limiting
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));

// 7. HTTPS redirect in production
app.use((req, res, next) => {
  if (process.env.NODE_ENV === 'production' && !req.secure) {
    return res.redirect(301, `https://${req.headers.host}${req.url}`);
  }
  next();
});

// ── Routes ────────────────────────────────────────────────────────────────────

app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

// Protected route — add requireAuth middleware (see C1 recommendation)
app.get('/users', requireAuth, async (req, res, next) => {
  try {
    const users = await userService.findAll();
    res.json(users.map(({ id, name }) => ({ id, name }))); // omit PII fields
  } catch (err) {
    next(err);
  }
});

// ── Global error handler (MUST be last) ──────────────────────────────────────
app.use((err, req, res, next) => {
  console.error(err);
  res.status(err.statusCode ?? 500).json({
    error: (err.statusCode ?? 500) < 500 ? err.message : 'Internal server error',
  });
});

app.listen(process.env.PORT ?? 3000, () => {
  console.log(`Server running on port ${process.env.PORT ?? 3000}`);
});

module.exports = app;
```

**Dependencies to add:**
```bash
npm install helmet cors morgan express-rate-limit jsonwebtoken
```

